SELECT yield, batch_number
FROM manufacturing
WHERE design_id = 1;

SELECT design_name, status
FROM designs
ORDER BY status;

SELECT AVG(lead_time) AS average_lead_time
FROM supply_chain
WHERE vendor = 'VendorB';

SELECT component_id, typical_power
FROM power_specs
WHERE typical_power > 1.0;

SELECT component_id, quantity
FROM design_components
WHERE design_id = 1;

SELECT COUNT(component_id) AS component_count
FROM design_components
WHERE design_id = 1;
